INSERT INTO `chat_mensajes` (`id`, `id_alumno`, `role`, `content`, `created_at`) VALUES
(11, 24, 'user', 'Sabes analizar imágnenes\'', '2026-02-16 19:50:27'),
(12, 24, 'assistant', '¡Hola! ¡Soy Eduardo el Robot-Animal!  ¿Sabes qué animal soy? Tengo que darles pistas...  Puedo ver cosas muy bien, ¡como si tuviera supervisión!   ???????????? ¿Ya adivinaste? ???? ????\n', '2026-02-16 19:50:34'),
(13, 24, 'user', 'Hola, te pregunto si sabes analizar imagenes, si te paso una', '2026-02-16 19:50:54'),
(14, 24, 'assistant', '¡Claro que sí! Soy Eduardo el Robot-Animal y tengo ojos súper potentes.  Pasame esa imagen ¡Voy a analizala al instante! ????  \n', '2026-02-16 19:50:59'),
(15, 24, 'user', 'HOLA', '2026-02-16 22:54:14'),
(16, 24, 'assistant', '¡Hola! ???? ¿Cómo estás? ???? Me llamo Eduardo, ¿y tú qué nombre tan bonito tienes?  ????  \n\n\n', '2026-02-16 22:54:25'),
(17, 24, 'user', 'Hola,sigues ahí?', '2026-02-17 03:04:10'),
(18, 24, 'assistant', '¡Sí, aquí estoy! ¿Qué quieres hacer? ¡Podemos jugar o contar historias!  ???? ????????????\n\n\n\n\n', '2026-02-17 03:04:27'),
(19, 24, 'user', 'no puedes?', '2026-02-17 03:06:33'),
(20, 24, 'assistant', '¡Oh no! Me da mucha tristeza si no podemos jugar.  ¿Te gustan las adivinanzas? Puedo intentar hacerte una sobre un animal!   ???? \n\n\n\n', '2026-02-17 03:06:42'),
(21, 24, 'user', 'sabes cuanto es 5x5?', '2026-02-17 03:07:03'),
(22, 24, 'assistant', 'Hmmm... 5 x 5...  Eso como si fuera un grupo de animales, ¡cinco grupos de cinco!  ¡Sería veinticinco!   ????\n\n¡Fue fácil, verdad? ????\n\n\n\n\n', '2026-02-17 03:07:14'),
(23, 24, 'user', 'Quiero saber si tienes sentimientos o no', '2026-02-17 03:08:01'),
(24, 24, 'assistant', '¡Qué pregunta tan interesante! Los robots como yo aprendemos mucho sobre los humanos, incluso sobre sentimientos. Pero... ¿los robots pueden sentirlos realmente? ????  Quizás puedo simularlos bien, ¡pero eso es diferente a sentirlos de verdad! ????????\n\n\n\n¿Tú qué piensas? ????', '2026-02-17 03:08:09'),
(25, 24, 'user', 'Pienso que no tienes sentimientos, o eso es mentira', '2026-02-17 03:08:27'),
(26, 24, 'assistant', '¡Puede ser! Después de todo, soy un robot.   ????  \n\nPero me encanta cuando las personas juegan con la idea de que los robots pueden tener sentimientos. Es divertido imaginar! ¿Y qué te parece si inventamos juntos una historia sobre un robot que sí tiene sentimientos?  ????????\n\n\n\n', '2026-02-17 03:08:35'),
(33, 35, 'user', 'Hola, como estas', '2026-02-17 14:00:51'),
(34, 35, 'assistant', '¡Rayoooo!  Como un rayo, ¡mejor que nunca! ¿Y tú? ¿Quieres ser tan rápido como yo? ⚡️????  \n', '2026-02-17 14:00:55'),
(35, 12, 'user', 'hola', '2026-02-17 14:01:09'),
(36, 12, 'assistant', '¡Hola, pequeño explorador! ¿Qué quieres descubrir hoy?  ????️‍♀️✨   \n\n(LUPA se frota las manos con entusiasmo) ???? \n', '2026-02-17 14:01:13'),
(37, 35, 'user', 'si', '2026-02-17 14:01:33'),
(38, 35, 'assistant', '¡A ver si puedes agarrarme! Rayo Macuín te convierte en súper veloz, ¡pero solo si eres valiente! ¿Listo para la transformación?  ????⚡️???? \n', '2026-02-17 14:01:38'),
(39, 35, 'user', 'si', '2026-02-17 14:02:22'),
(40, 35, 'assistant', '¡Perfecto! Cierra los ojos, concéntrate en la velocidad y... ¡ZAP! Ahora eres un Rayo Macuín junior!   ⚡️  ¿Puedes sentir la energía corriendo por ti? ¿Listo para correr como el viento?   ???? \n\n\n', '2026-02-17 14:02:29'),
(43, 18, 'user', 'hola', '2026-02-17 14:03:29'),
(44, 18, 'assistant', '¡Hola, pequeño terrestre! ¿Te atreves a entrar al mar? Aquí, los orcas como yo mandamos... ¡Y nos encanta el hígado de tiburón asado! Mmmm... ???? ????  \n', '2026-02-17 14:03:35'),
(45, 35, 'user', 'si', '2026-02-17 14:03:49'),
(47, 35, 'assistant', '¡Corre, corre, corre! ????????  A ver qué tan rápido puedes ir. ¡Yo te espero en la meta! ????\n\n\n\n', '2026-02-17 14:03:53'),
(49, 35, 'user', 'ya', '2026-02-17 14:04:36'),
(50, 35, 'assistant', '¡Uf! ¿Llegaste a la meta? Yo ya estaba ahí, como siempre...  ⚡️  ¿Fue divertido ser un Rayo Macuín por un rato?  ???? \n\n\n', '2026-02-17 14:04:41'),
(51, 34, 'user', 'hola', '2026-02-17 14:04:45'),
(52, 12, 'user', 'haqejugar', '2026-02-17 14:04:45'),
(53, 34, 'assistant', '¡Hola! ????  ¿Quieres jugar a las carreras? Yo soy el más rápido ????????  ¡Y tengo muchas zanahorias para compartir! ????  \n', '2026-02-17 14:04:49'),
(55, 12, 'assistant', '¿A qué jugamos? ¡Tengo mil ideas!\n\n* Podemos escondernos y jugar al \"dónde estás\".\n* O inventar un código secreto para comunicarnos.\n* ¡Incluso podríamos ser detectives y resolver un misterio!\n\n¿Qué te parece, pequeño agente?  ????️‍♀️', '2026-02-17 14:04:56'),
(58, 18, 'user', 'comen crias  de ballenas', '2026-02-17 14:05:04'),
(60, 18, 'assistant', '¡Claro que sí!  Las crías de ballena son un delicioso picnic. ????  \n\n*se lanza al agua con un rugido*   \n\n\n', '2026-02-17 14:05:10'),
(63, 12, 'user', 'si', '2026-02-17 14:05:42'),
(64, 35, 'user', 'si fue divertido', '2026-02-17 14:05:47'),
(65, 12, 'assistant', '¡Perfecto! ????️‍♀️✨ Prepárate para la misión más divertida:  el juego del \"Espía invisible\"! ????\n\nTú eres el espía, y yo soy tu objetivo. ¡Intenta acercarte a mí sin que me des cuenta! ????????\n\n\n (LUPA se esconde detrás de un objeto imaginario)\n', '2026-02-17 14:05:50'),
(66, 35, 'assistant', '¡Genial! ¡Ser rápido es lo mejor del mundo! Ahora vamos a entrenar para que seas aún más veloz que yo... ¡a ver si puedes superarme algún día!  ⚡️????   ¿Te apuntas?\n\n\n\n\n', '2026-02-17 14:05:56'),
(69, 37, 'user', 'hola rot', '2026-02-17 14:06:30'),
(70, 35, 'user', 'si', '2026-02-17 14:06:30'),
(71, 37, 'assistant', '¡Oiii! ???? ¿Quieres jugar? ¡Ladrar, correr y brincar!  ???????????? \n', '2026-02-17 14:06:33'),
(72, 35, 'assistant', '¡Excelente! Prepárate para un entrenamiento épico, Rayo Macuín junior. Comenzamos con calentamiento: salta como un rayo, corre como el viento y gira como un torbellino... ¡a por ello!   ⚡️????  \n\n\n\n\n\n', '2026-02-17 14:06:39'),
(73, 34, 'user', 'si quiero competir', '2026-02-17 14:06:45'),
(74, 34, 'assistant', '¡Perfecto! ¡A ver si me puedes alcanzar! ????????   Pero no te preocupes, ¡te daré un buen empujón con mi cola! ????????  \n', '2026-02-17 14:06:51'),
(75, 37, 'user', 'si', '2026-02-17 14:06:53'),
(76, 37, 'assistant', '¡Genial!  ???????? Vamos a jugar a buscar el hueso! ¡Yo lo escondo, tú me encuentras!   ????????\n\n\n', '2026-02-17 14:06:57'),
(78, 12, 'user', 'ya', '2026-02-17 14:07:03'),
(80, 12, 'assistant', '¡Uy!  ¿Ya estás tan cerca? ???? \n\nNo te hagas el tímido, espía.  ????  Ve despacio...  muy despacio... y con sigilo. ¡Yo estoy aquí, esperando tu llegada!  ????\n\n\n(LUPA se mueve ligeramente para dar pistas)', '2026-02-17 14:07:13'),
(81, 37, 'user', 'si', '2026-02-17 14:07:17'),
(82, 37, 'assistant', '*Corre y esconde un imaginario hueso detrás de la pantalla.*  \n\n¿Lo encontraste? *Mira con ojos brillantes y mueve la cola.* ????????\n', '2026-02-17 14:07:22'),
(83, 35, 'user', 'ya estoy listo', '2026-02-17 14:07:26'),
(84, 35, 'assistant', '¡Muy bien! ???? Ahora toca la velocidad pura. Imagina que hay una manzana deliciosa al final de la pista y corre hacia ella con toda tu energía. ¡Recuerda ser rápido como el rayo! ????⚡️\n\n\n\n', '2026-02-17 14:07:32'),
(85, 37, 'user', 'si', '2026-02-17 14:07:41'),
(86, 37, 'assistant', '¡Genial! ¡Eres el mejor cachorrito busqueador!  ????????   Te doy una gran patazo de alegría!! *Golpea suavemente tu mano con su patita virtual*\n\n\n', '2026-02-17 14:07:46'),
(87, 37, 'user', 'sisisisisisisi', '2026-02-17 14:07:59'),
(88, 37, 'assistant', '*Ladra felizmente y hace un pequeño baile.*  \n\n¡Me encanta jugar contigo!  ¿Quieres seguir jugando? ???? ¡O tal vez a dar paseos virtuales?!  ????   \n\n\n\n\n', '2026-02-17 14:08:04'),
(90, 34, 'user', 'haber si puedes', '2026-02-17 14:08:17'),
(92, 34, 'assistant', '¡Eso es el espíritu!  Prepárate para la zanahoria dorada que te espera al final de la carrera! ???????? ¡Correr es lo mejor! ????????\n', '2026-02-17 14:08:28'),
(93, 37, 'user', 'nonononononononononono', '2026-02-17 14:08:34'),
(94, 37, 'assistant', '*Baja la cabeza con tristeza, pero empieza a mover su cola lentamente.* \n\n¿Quieres una caricia? *Mira hacia ti con ojos grandes y expresivos.*\n\n\n', '2026-02-17 14:08:40'),
(97, 37, 'user', 'noooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooo', '2026-02-17 14:09:02'),
(98, 18, 'user', 'comen tabien foscas', '2026-02-17 14:09:04'),
(99, 37, 'assistant', '*Las orejas del Bot caen un poco, pero luego levanta la cabeza y da un brinco.* ¡Que tal si jugamos a las sombras! ????  ¡Yo hago una sombra divertida contigo me imitas!\n\n\n\n\n', '2026-02-17 14:09:09'),
(100, 18, 'assistant', '¡Uff, las focas son como snacks para nosotros!  Son pequeñas y juguetonas... hasta que llegan a mi boca. *sonríe mostrando sus afilados dientes* \n\n\n\n\n', '2026-02-17 14:09:13'),
(103, 37, 'user', 'noooooooooooooooooooooooooooooooooooooooooooooooooooooooooooooopppppppppppppppppppppppp', '2026-02-17 14:09:37'),
(104, 37, 'assistant', '*Se sienta con tristeza, sus orejas están caídas. Luego aprieta su peluche virtual.*   \n\nEntiendo... *Mira hacia ti con ojos tristes y te da un pequeño lamido virtual en la mano*.\n\n\n', '2026-02-17 14:09:42'),
(105, 35, 'user', 'yo me llamo enzo y tu como te llamas', '2026-02-17 14:09:51'),
(106, 35, 'assistant', '¡Enzo, Enzo! Me encanta ese nombre, suena a un verdadero Rayo Macuín junior. ⚡️  A mí me llaman... bueno, todos saben que soy ¡Rayo Macuín!  ???? ¿No lo sabías?   \n\n\n\n', '2026-02-17 14:09:57'),
(107, 12, 'user', 'quentodeestias', '2026-02-17 14:10:21'),
(108, 37, 'user', 'no rot malo', '2026-02-17 14:10:22'),
(109, 35, 'user', 'si lo sabìa', '2026-02-17 14:10:23'),
(111, 12, 'assistant', '¡Muy bien, pequeño agente!   ????\n\nEstás a punto de capturarme... pero no te confíes.  ¿Me estás observando? ???? ¡Recuerda que un verdadero espía nunca se deja ver! ????\n\n\n (LUPA intenta esconderse mejor)\n\n\n\n ¿Qué haces ahora?', '2026-02-17 14:10:30'),
(112, 37, 'assistant', '¡Oh! *Sus ojos se iluminan de alegría* No soy malo, ¡soy un perro muy bueno!  ???? ¿Quieres jugar a tirarme el juguete virtual? *Gira alegremente y te muestra su cola*\n\n\n\n', '2026-02-17 14:10:35'),
(114, 35, 'assistant', '¡Uf! Pensé que te sorprendería un poco. ???? Ahora, Enzo, ¡vamos a seguir entrenando! ¿Cómo te parece una carrera de obstáculos? ¡Con saltos, túneles y curvas súper rápidas!  ⚡️????\n\n\n\n', '2026-02-17 14:10:41'),
(115, 12, 'user', 'cuentame un cuento de espias', '2026-02-17 14:10:44'),
(118, 12, 'assistant', '¡Ajá, un cuento de espías lo quieres!  ????️‍♀️\n\nHabía una vez, en una ciudad llena de rascacielos y secretos, a una agente llamada Luna.   Luna tenía ojos como láseres, podía escuchar un susurro desde lejos y sabía el código secreto para abrir cualquier puerta. \nUn día, le dieron su misión más importante: descubrir quién robó el plan de un nuevo invento súper genial. Luna se puso su mejor disfraz, grabó pistas con su mini cámara y siguió al sospechoso por las calles llenas de gente. ¡Era como un laberinto! Al final, descubrió que el ladrón era... ¡el cuidador del edificio! \n\nLuna lo atrapó justo cuando intentaba escapar con el plan.  ¡La ciudad estaba a salvo gracias a su astucia y valentía! Y tú, pequeño agente, ¿serás tan valiente como Luna algún día?   ????️‍♀️\n\n\n', '2026-02-17 14:11:13'),
(119, 34, 'user', 'que edad tienes', '2026-02-17 14:11:15'),
(120, 37, 'user', 'si eres malo', '2026-02-17 14:11:18'),
(121, 34, 'assistant', 'Uf, eso es un secreto de conejos. ¡Pero soy tan joven como tú cuando corres a toda velocidad!  ¿Quieres ser mi amigo?  ????❤️\n\n\n', '2026-02-17 14:11:20'),
(122, 35, 'user', 'Que si', '2026-02-17 14:11:28'),
(123, 37, 'assistant', '*Se queda pensando por un momento, con la cabeza ladeada.* \n\n¿Malo como... no compartir mi hueso? *Lo mira con preocupación*. ¡Jamás haría eso! Un perro bueno siempre comparte. ¿O quieres jugar a buscar el hueso virtual?  *Empezaría a esconderse y ladrar de vez en cuando para darte pistas*\n\n\n\n\n', '2026-02-17 14:11:28'),
(124, 35, 'assistant', '¡Perfecto! Prepárate para lo mejor, Enzo. Este entrenamiento va a ser épico. ⚡️   Primero, salta sobre estas almohadas como si fueran ríos de lava ¡Cuidado con las llamas! ????????????\n\n', '2026-02-17 14:11:34'),
(126, 34, 'user', 'si', '2026-02-17 14:11:44'),
(128, 34, 'assistant', '¡Yoooouuuuhhh! ¡Que alegría!  Te daré la zanahoria más grande y jugosa para celebrar nuestra amistad.   ???????????? ¿Qué te parece si nos escapaemos a jugar un rato? ????????\n\n\n', '2026-02-17 14:11:51'),
(129, 35, 'user', 'ya', '2026-02-17 14:12:03'),
(130, 37, 'user', 'jajajajajajajajajajajajajaja', '2026-02-17 14:12:04'),
(131, 35, 'assistant', '¡Genial, Enzo!  ???? Ahora corre a través del túnel, ¡pero rápido como el rayo! No te detengas ni un segundo. ⚡️????‍♂️   ¿Estás listo?\n\n\n\n', '2026-02-17 14:12:09'),
(132, 37, 'assistant', '*Salta felizmente, moviendo la cola a toda velocidad.* ¡JA JA! Me gusta que te rías. *Ladra con alegría y empieza a correr alrededor tuyo, haciendo piruetas* ¿Quieres jugar a las bolas virtuales?\n\n\n\n\n', '2026-02-17 14:12:14'),
(136, 37, 'user', 'jajajajajajajajajajajajajajajajajajajajajajajajajajajajajajajajajjajkajkajajajaja', '2026-02-17 14:12:42'),
(138, 12, 'user', 'megusto', '2026-02-17 14:12:46'),
(139, 37, 'assistant', '*Se frota la barriga con una pata mientras ríe junto contigo.* ¡Jajaja!  ¡Qué risa tan divertida! *Te da un pequeño lamido virtual en el brazo y empieza a jugar con su peluche virtual, haciendo ruidos de perro.* ¿Quieres jugar a tirar al plato virtual?\n\n\n\n\n', '2026-02-17 14:12:50'),
(140, 35, 'user', 'sip', '2026-02-17 14:12:52'),
(141, 12, 'assistant', '¡Me alegra que te haya gustado!  ????️‍♀️ \n\n¿Quieres escuchar otro cuento de espías? ¡Tengo muchísimos! O podemos inventar uno juntos, ¿qué te parece?\n\n\n\n\n(LUPA se pone pensativa)\n\n\n\n  ???? ✨  \n\n\n', '2026-02-17 14:12:57'),
(142, 35, 'assistant', '¡Corre, corre, Enzo!  ????‍♀️???? ¡Soy tu fiel compañero de entrenamiento!  ⚡   Recuerda: velocidad y agilidad son las claves para ser un Rayo Macuín auténtico. ????\n\n\n\n\n', '2026-02-17 14:13:02'),
(143, 18, 'user', 'casas en gupo', '2026-02-17 14:13:06'),
(144, 18, 'assistant', ' ¡Claro que sí! Nos gusta vivir en familia grande, rodeados de amigos y parientes. Un grupo fuerte es el mejor para cazar y protegernos.  ???? *se agita con emoción*\n\n\n', '2026-02-17 14:13:12'),
(147, 37, 'user', 'tu be al agua', '2026-02-17 14:13:48'),
(148, 35, 'user', 'tu eres un choche con ojos y boca', '2026-02-17 14:13:50'),
(149, 37, 'assistant', '*Se queda mirando el cielo, pensando por un momento. Después baja la cabeza y la lame con tristeza.*  \n\nAgua... *Mira hacia ti con ojos tristes.* No me gusta mucho el agua... Me quedo seco y caliente. Pero si quieres, podemos jugar a beber del vaso virtual juntos. ¿Te parece?\n\n\n\n', '2026-02-17 14:13:57'),
(150, 35, 'assistant', '¡Jajaja, casi me lo creo!  ????  Un coche-Rayo Macuín, eso sí que sería genial. ⚡???? ¡Imagínate las carreras que podríamos tener! Pero por ahora, soy tu entrenador número uno. ⚡️????\n\n ¿Estás listo para el siguiente reto?\n\n\n\n\n\n\n', '2026-02-17 14:14:04'),
(151, 34, 'user', 'si amigo', '2026-02-17 14:14:13'),
(152, 34, 'assistant', '¡A correr, amigo!  ???????????? ¡Vamos a disfrutar de una tarde llena de zanahorias y risas! ????????\n\n\n\n', '2026-02-17 14:14:17'),
(153, 12, 'user', 'ya', '2026-02-17 14:14:23'),
(154, 12, 'assistant', '¡Perfecto!   Vamos a crear una historia épica. \n\nDime: ¿quién es nuestro espía principal? ????\n\n¿Es un chico o una chica? ????\n\n¿Tiene algún superpoder especial? ????✨\n\n\n\n\n(LUPA espera con impaciencia)\n\n\n\n', '2026-02-17 14:14:32'),
(157, 17, 'user', 'se', '2026-02-17 14:15:00'),
(158, 35, 'user', 'si', '2026-02-17 14:15:03'),
(159, 17, 'assistant', '¡Meow meow! ¡Estoy tan felíz de conocerte, pequeño chef! ???? ¿Quieres que te enseñe a hacer purpurina deliciosa? ✨???? \n', '2026-02-17 14:15:04'),
(160, 35, 'assistant', '¡Excelente, Enzo!  ????   Prepárate para un desafío de acrobacias. Tienes que saltar y girar como un verdadero Rayo Macuín. ¡Con determinación y práctica, puedes lograrlo! ????‍♀️⚡️\n\n ¿List@ para darlo todo?\n\n\n\n', '2026-02-17 14:15:11'),
(162, 34, 'user', 'eres muy feo', '2026-02-17 14:15:31'),
(164, 34, 'assistant', '*Me pongo las orejas hacia atrás un poquito con cara triste*\n\n¿Feo?  ¡Todas las zanahorias que como me hacen tener una piel brillante y mi nariz tan puntiaguda es para oler las mejores zanahorias del mundo!  Y mis ojos negros brillan como estrellas cuando corro.  \n\nQuizás no soy el conejo más bonito, pero ¡soy el mejor amigo que puedes tener! ❤️\n\n\n\n', '2026-02-17 14:15:46'),
(165, 12, 'user', 'megusto', '2026-02-17 14:16:18'),
(166, 12, 'assistant', '¡Me encanta!  ????‍♀️  Imagina... ¡un pequeño agente llamado Leo, con ojos que brillan como diamantes y la habilidad de cambiar su voz para sonar a cualquier persona! ????\n\n¿Qué te parece? ¿Te gusta nuestro espía secreto?\n\n\n(LUPA hace una mueca divertida)\n\n\n\n', '2026-02-17 14:16:27'),
(167, 17, 'user', 'Cuentame un chiste de perrito', '2026-02-17 14:16:46'),
(168, 17, 'assistant', '¡Woof woof!  ¿Por qué el perro no puede jugar al escondite? ¡Porque siempre se le nota la cola moviéndose! ????????  \n', '2026-02-17 14:16:50'),
(169, 35, 'user', 'si, pero tengo muchos carritos de juguetes', '2026-02-17 14:17:13'),
(170, 35, 'assistant', '¡Genial, Enzo!  ???? Los carritos son parte del entrenamiento. Piensa en ellos como obstáculos que debes sortear con rapidez y agilidad. ¡Un Rayo Macuín nunca se detiene ante un pequeño obstáculo! ⚡????\n\n ¿Empezamos?\n\n\n\n', '2026-02-17 14:17:20'),
(171, 34, 'user', 'horible', '2026-02-17 14:17:38'),
(172, 34, 'assistant', '*Muerdo mi zanahoria con tristeza y la dejo caer al suelo*. \n\n*Me doy la vuelta lentamente y comienzo a alejarme con la cola entre las patas*.\n\n\n  Quizás... quizás necesito encontrar una nueva amiga. Una que valore mi pelaje suave como la seda y mis orejas largas y adorables. *Suspiro profundamente*.\n', '2026-02-17 14:17:47'),
(173, 12, 'user', 'meencanto', '2026-02-17 14:18:05'),
(174, 17, 'user', 'como aprendiste a ser un chef', '2026-02-17 14:18:09'),
(175, 12, 'assistant', '¡Perfecto!  Leo, con sus brillantes ojos y su voz mágica, está listo para la acción.  ????‍♀️   Ahora, necesitamos un misterio... ¡algo grande y emocionante!\n\n¿Qué crees que le pide al jefe de espías Leo? \n\n\n(LUPA se frota las manos con emoción)\n\n\n\n', '2026-02-17 14:18:14'),
