(10, 21, 'hansel y gretel', '', '', '', '', '', '', '2026-02-13 16:16:04', 'bottom', 'bottom', 'bottom', 'bottom', 'bottom', 'bottom', '{\"bubbles\":[{\"x\":464,\"y\":328,\"w\":150,\"h\":90,\"text\":\"\",\"fs\":16,\"type\":\"shout\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":221,\"y\":108,\"w\":150,\"h\":90,\"text\":\"\",\"fs\":16,\"type\":\"normal\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null}],\"chars\":[]}', '{\"bubbles\":[],\"chars\":[]}', '{\"bubbles\":[],\"chars\":[]}', '{\"bubbles\":[],\"chars\":[]}', '{\"bubbles\":[],\"chars\":[]}', '{\"bubbles\":[],\"chars\":[]}'),
(11, 19, 'la muñeca  maldita ', '', '', '', '', '', '', '2026-02-13 16:16:08', 'bottom', 'bottom', 'bottom', 'bottom', 'bottom', 'bottom', '{\"bubbles\":[{\"x\":16,\"y\":7,\"w\":542,\"h\":69,\"text\":\"una mujer en plena lluvia caminaba y encontro una muñeca con un vestido blanco y marcas y la mujer dijo .\",\"fs\":16,\"type\":\"box\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":110,\"y\":61,\"w\":150,\"h\":90,\"text\":\"la voy a dar a mi hija para que juege con ella \",\"fs\":16,\"type\":\"thought\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null}],\"chars\":[{\"x\":-664,\"y\":113,\"w\":1604,\"h\":280,\"src\":\"http://192.168.1.179/iaparateens/uploads/782ebfdc5e1301b6ec09fa4bdee880b7.jpg\",\"z\":50,\"f\":false,\"l\":false}]}', '{\"bubbles\":[{\"x\":-15,\"y\":5,\"w\":582,\"h\":71,\"text\":\"la mujer le dio la muñeca a su hija la niña estaba feliz y le dijo la niña  \",\"fs\":16,\"type\":\"box\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":201,\"y\":87,\"w\":150,\"h\":90,\"text\":\"¡grasias mamà me encanto la muñeca !\",\"fs\":16,\"type\":\"normal\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":21,\"y\":84,\"w\":150,\"h\":90,\"text\":\"de nada hija como le vas a llamar \",\"fs\":16,\"type\":\"normal\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null}],\"chars\":[{\"x\":-94,\"y\":99,\"w\":528,\"h\":232,\"src\":\"http://192.168.1.179/iaparateens/uploads/c18e6ae3e04743e8d10d0cdfc17edd5b.png\",\"z\":50,\"f\":false,\"l\":false}]}', '{\"bubbles\":[{\"x\":-38,\"y\":5,\"w\":707,\"h\":88,\"text\":\"pasaron los días y la muñeca desapareció la madre la busco por toda la casa y no la encontró asta un día la muñeca regreso toda llena de sangre su vestido y la niña grito , su mamá vino corriendo y lo vio y le susurro a la niña \",\"fs\":16,\"type\":\"box\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":132,\"y\":119,\"w\":150,\"h\":90,\"text\":\"mamá mamá ven mira \",\"fs\":16,\"type\":\"shout\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":474,\"y\":103,\"w\":150,\"h\":90,\"text\":\"temos que botarla al lago \",\"fs\":16,\"type\":\"whisper\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null}],\"chars\":[]}', '{\"bubbles\":[{\"x\":-85,\"y\":3,\"w\":687,\"h\":88,\"text\":\"la mamá y la niña la votaron al lago pera la muñeca le estaba arrancando su brazo a la niña la mujer saco ala muñeca de su hija pero la muñeca tenia un cuchillo y corto su brazo de la niña\",\"fs\":16,\"type\":\"box\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":44,\"y\":113,\"w\":150,\"h\":90,\"text\":\"mami alluda \",\"fs\":16,\"type\":\"shout\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":397,\"y\":106,\"w\":150,\"h\":90,\"text\":\"no mi hija \",\"fs\":16,\"type\":\"shout\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null}],\"chars\":[]}', '{\"bubbles\":[{\"x\":0,\"y\":1,\"w\":588,\"h\":85,\"text\":\"la muñeca salió del lago y le  corto  su cabeza de la niña y la madre se fue corriendo y a la mañana siguiente en la puerta de su casa encontro la cabeza de su hija \",\"fs\":16,\"type\":\"box\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null},{\"x\":352,\"y\":104,\"w\":150,\"h\":90,\"text\":\"aaaaaaaaaaaaaaaa¡\",\"fs\":16,\"type\":\"shout\",\"z\":100,\"f\":false,\"l\":false,\"bg\":null,\"fn\":null}],\"chars\":[]}', '{\"bubbles\":[],\"chars\":[]}'),
