INSERT INTO `preguntas` (`id`, `examen_id`, `enunciado`, `tipo`, `opciones`, `respuesta_correcta`, `orden`) VALUES
(13, 11, '¡Qué es una IA?', 'opcion_multiple', '{\"A\":\"Un animal\",\"B\":\"Una persona\",\"C\":\"Una máquina\",\"D\":\"Un perrito\"}', 'C', 0),
(14, 11, '¿Cuál es una aplicación común de las IAs?', 'opcion_multiple', '{\"A\":\"Reparación de Automóviles\",\"B\":\"Cocinar Comida\",\"C\":\"Conducir un Avión \",\"D\":\"Identificar Enfermedades\"}', 'D', 0),
(16, 11, '¿Qué es el aprendizaje automático (machine learning)?', 'opcion_multiple', '{\"A\":\"Un entrenamiento que se le hace a la Inteligencia Artificial para que aprenda\",\"B\":\"Un método para reparar computadoras\",\"C\":\"Una forma de comunicación\",\"D\":\"Un programa de televisión\"}', 'A', 0),
(17, 11, '¿Cómo se le llama al proceso de enseñar a una IA?', 'opcion_multiple', '{\"A\":\"Programación \",\"B\":\"Entrenamiento\",\"C\":\"Desarrollo \",\"D\":\"Evolución\"}', 'B', 0),
(18, 11, '¿Cuál es el desafío para el desarrollo de IAs?', 'opcion_multiple', '{\"A\":\"Exceso de programadores \",\"B\":\"Falta de presupuesto\",\"C\":\"Exceso de tiempo\",\"D\":\"Falta de datos\"}', 'D', 0),
(19, 11, '¿Puede la IA volverse más inteligente que un humano?', 'opcion_multiple', '{\"A\":\"Sí, en todas las áreas\",\"B\":\"Sí, pero solo en algunas áreas\",\"C\":\"No, la IA siempre tiene limitaciones\",\"D\":\"Depende\"}', 'B', 0),
(20, 12, '¿A qué se parece más la Inteligencia Artificial (IA)?', 'opcion_multiple', '{\"A\":\"A un niño que juega solo.\",\"B\":\"A un robot muy obediente que sigue instrucciones\",\"C\":\"A una mascota que no hace caso\",\"D\":\"A un animal\"}', 'B', 0),
(21, 12, 'Para que la IA haga un dibujo bonito, ¿qué necesita que le demos?', 'opcion_multiple', '{\"A\":\"Caramelos.\",\"B\":\"Instrucciones claras llamadas \\\"Prompts\\\".\",\"C\":\"Un abrazo\",\"D\":\"Un beso\"}', 'B', 0),
(22, 12, 'Si tú eres el \\\"entrenador\\\" y le dices a la IA: \\\"Dibuja un pato\\\", pero no le dices el color... ¿De qué color lo pintará?', 'opcion_multiple', '{\"A\":\"¡De cualquier color, porque no fuimos claros!\",\"B\":\"Siempre amarillo.\",\"C\":\"No dibujará nada.\",\"D\":\"De ningún color\"}', 'A', 0),
(23, 12, '¿Cuál de estos es un \\\"Prompt\\\" (instrucción) perfecto para un robot dibujante?', 'opcion_multiple', '{\"A\":\"Dibuja\",\"B\":\"Haz algo ahí\",\"C\":\"Dibuja un círculo grande y rojo\",\"D\":\"Compórtate como un diseñador gráfico y dibuja un circulo rojo.\"}', 'D', 0),
(24, 12, 'En Minecraft, si queremos construir una torre de piedra, ¿qué debemos decirle a nuestra imaginación (IA)?', 'opcion_multiple', '{\"A\":\"Haz una casa\",\"B\":\"IA, pon bloques\",\"C\":\"IA, construye una torre de piedra con bloques\",\"D\":\"Haz algo\"}', 'C', 0),
(25, 12, '¿La Inteligencia Artificial puede pensar solita como nosotros?', 'opcion_multiple', '{\"A\":\"SÍ, ella decide todo\",\"B\":\"NO, ella necesita que nosotros le demos el \\\"poder de las palabras\\\"\",\"C\":\"Puede ser\",\"D\":\"Creo que sí\"}', 'B', 0),
(26, 11, '¿Qué es exactamente un \\\'Prompt\\\' en el contexto de la IA Generativa?', 'opcion_multiple', '{\"A\":\"Un programa de computadora que dibuja solo\",\"B\":\"El nombre del robot que construye en minecraft\",\"C\":\"Un error que hace que las computadoras se apaguen\",\"D\":\"Una instrucción o descripción en nuestro lenguaje que le damos a la IA\"}', 'D', 0),
(27, 11, '¿De dónde obtiene la IA Generativa la información para saber cómo es una \\\'casa de piedra\\\' o un \\\'pato\\\'?', 'opcion_multiple', '{\"A\":\"Lo inventa todo por arte de magia.\",\"B\":\"De una base de datos gigante llamada \'Dataset\' (como internet).\",\"C\":\"Solo de lo que tú le escribes en ese momento.\",\"D\":\"Ella nace sabiendo todo lo que existe.\"}', 'B', 0),
(28, 11, 'Si queremos que la IA nos de un mejor resultado, primero debernos darle un: ', 'opcion_multiple', '{\"A\":\"Un Rol, como queremos que se comporte\",\"B\":\"Los buenos días\",\"C\":\"Unos textos muy largos\",\"D\":\"Un par de palabras\"}', 'A', 0),
(29, 11, 'Para que la IA nos genere una imagen  y se parezca lo mejor posible al que queremos, como debe estar estructurado el promt:', 'opcion_multiple', '{\"A\":\"primero le damos un estilo, luego una acción, luego un entorno y por último un rol.\",\"B\":\"primero le damos un rol, luego el personaje, luego una acción, luego un entorno y por último el estilo.\",\"C\":\"primero le damos un entorno, luego el personaje, luego una acción, luego un entorno y por último el rol.\",\"D\":\"primero le damos una acción, luego el rol, luego una emoción, luego un entorno y por último el estilo.\"}', 'B', 0),
(30, 13, '1. ¿Qué es la \\\"Clasificación\\\" en la Inteligencia Artificial?', 'opcion_multiple', '{\"A\":\"A) Cuando la IA se pone a dormir.\",\"B\":\"B) El proceso de agrupar cosas por sus características (como separar frutas de verduras).\",\"C\":\"C) Un juego de carreras para robots.\",\"D\":\"D) Cuando la IA borra toda su memoria.\"}', 'B', 0),
(31, 13, '2. En el Aprendizaje por Refuerzo, cuando la IA hace algo bien, le damos un \\\"premio\\\" llamado...', 'opcion_multiple', '{\"A\":\"A) Chocolate de verdad\",\"B\":\"B) Recompensa o punto positivo\",\"C\":\"C) Un jalón de orejas\",\"D\":\"D) Una medalla de papel\"}', 'B', 0),
(32, 13, 'Para que una IA aprenda a separar fotos de \\\"Frutas\\\" y \\\"Verduras\\\", necesita ver...', 'opcion_multiple', '{\"A\":\"A) Muchos ejemplos para no confundirse. (Correcta)\",\"B\":\"B) Solo una foto y ya.\",\"C\":\"C) Una película de acción.\",\"D\":\"D) Nada, la IA lo sabe por magia.\"}', 'A', 0),
(33, 13, '6. El aprendizaje de \\\"Ensayo y Error\\\" significa que la IA...', 'opcion_multiple', '{\"A\":\"A) Aprende intentándolo muchas veces hasta que le sale bien.\",\"B\":\"B) Hace la tarea una sola vez y se va a jugar.\",\"C\":\"C) Siempre lo hace todo perfecto a la primera.\",\"D\":\"D) Espera a que el profesor le dé la respuesta.\"}', 'A', 0),
(34, 13, '¿A qué se parece entrenar a una IA con premios (refuerzo)?', 'opcion_multiple', '{\"A\":\"A) A ver cómo cae la lluvia.\",\"B\":\"B) A enseñarle a un perrito a dar la pata dándole una galleta.\",\"C\":\"C) A inflar un globo muy grande.\",\"D\":\"D) A comerse una sopa de verduras.\"}', 'B', 0),
(35, 13, '5. Si la IA clasifica una Manzana como si fuera un Plátano, ¿qué debemos hacer?', 'opcion_multiple', '{\"A\":\"A) Castigar a la computadora.\",\"B\":\"B) Darle más ejemplos y feedback para que aprenda el error.\",\"C\":\"C) Decirle que está bien para que no se sienta mal.\",\"D\":\"D) Borrar todo el programa.\"}', 'B', 0),
(36, 13, '7. ¿Para qué nos sirven las IAs que aprenden y crean cosas?', 'opcion_multiple', '{\"A\":\"A) Para que los humanos ya no tengan que usar su cerebro.\",\"B\":\"B) Solo sirven para que el monitor brille más fuerte.\",\"C\":\"C) Para que las computadoras se vuelvan las dueñas de la casa.\",\"D\":\"D) Para ayudarnos a hacer tareas difíciles o aburridas de forma divertida.\"}', 'D', 0),
(37, 13, '1. ¿Cuál es la función principal de una IA Generativa cuando recibe una instrucción del usuario?', 'opcion_multiple', '{\"A\":\"A. Crear contenido nuevo combinando patrones que aprendió anteriormente.\",\"B\":\"B. Buscar un archivo guardado y mostrarlo exactamente igual.\",\"C\":\"C. Borrar la memoria de la computadora para ahorrar espacio.\",\"D\":\"D. Apagar el sistema si la instrucción es muy difícil.\"}', 'A', 0),
(38, 13, '4. ¿Qué es un \\\'Dataset\\\' y por qué es importante para la Inteligencia Artificial?', 'opcion_multiple', '{\"A\":\"A. Es la clave secreta para entrar a internet.\",\"B\":\"B. Es el cable que conecta el monitor con la torre.\",\"C\":\"C. Es un programa para dibujar paisajes en 3D.\",\"D\":\"D. Es el conjunto de datos que la IA usa como material de estudio para aprender.\"}', 'D', 0),
(39, 13, '10. ¿Cuál es un beneficio real de que una IA aprenda a clasificar datos correctamente?', 'opcion_multiple', '{\"A\":\"A. Hacer que los videos de internet se vean en blanco y negro.\",\"B\":\"B. Que las computadoras puedan reemplazar a los humanos en todos los juegos.\",\"C\":\"C. Ayudar a organizar grandes cantidades de información de forma rápida y precisa.\",\"D\":\"D. Que el teclado de la computadora tenga más teclas.\"}', 'A', 0),
(40, 14, '1. Cuando una computadora usa su \\\"imaginación\\\" para inventar un dibujo de un dinosaurio que no existía, ¿cómo se llama esa IA?', 'opcion_multiple', '{\"A\":\"A) IA Dormilona.\",\"B\":\"B) IA Generativa (porque genera o crea cosas nuevas).\",\"C\":\"C) IA Rompecabezas.\",\"D\":\"D) IA de Juguete.\"}', 'B', 0),
(41, 14, '2. Si tienes una caja de piezas de LEGO y separas las rojas en un lado y las azules en otro, ¿qué estás haciendo?', 'opcion_multiple', '{\"A\":\"A) Clasificando (juntando cosas que se parecen).\",\"B\":\"B) Rompiendo los juguetes.\",\"C\":\"C) Pintando la casa.\",\"D\":\"D) Perdiendo el tiempo.\"}', 'A', 0),
(42, 14, '3. ¿Cómo aprende una IA a ganar muchos puntos en un juego?', 'opcion_multiple', '{\"A\":\"A) Leyendo un libro muy largo.\",\"B\":\"B) Intentándolo muchas veces y recibiendo \\\"premios\\\" cuando lo hace bien.\",\"C\":\"C) Pidiéndole permiso a su mamá.\",\"D\":\"D) No aprende, ya sabe jugar desde siempre.\"}', 'B', 0),
(43, 14, '4. ¿Qué es una \\\"Recompensa\\\" para la Inteligencia Artificial?', 'opcion_multiple', '{\"A\":\"A) Un caramelo de fresa.\",\"B\":\"B) Un punto positivo que le dice: \\\"¡Muy bien, sigue así!\\\".\",\"C\":\"C) Un martillo para arreglar cables.\",\"D\":\"D) Una foto de un gatito.\"}', 'B', 0),
(44, 14, '5. Si la IA quiere aprender a reconocer a un \\\"Perrito\\\", ¿qué necesita ver?', 'opcion_multiple', '{\"A\":\"A) Solo una foto de un perro.\",\"B\":\"B) Muchas fotos de diferentes perritos para aprender bien.\",\"C\":\"C) Una película de superhéroes.\",\"D\":\"D) Un dibujo de una manzana.\"}', 'B', 0),
(45, 14, '10. ¿Para qué queremos usar la Inteligencia Artificial?', 'opcion_multiple', '{\"A\":\"A) Para que haga nuestras travesuras.\",\"B\":\"B) Para que nos ayude a resolver problemas y tareas difíciles.\",\"C\":\"C) Para que las máquinas manden en la casa.\",\"D\":\"D) Para que la pantalla brille más bonito.\"}', 'B', 0),
(68, 18, 'Si le pides a la IA que sea un \"Capitán Pirata\", ¿cómo te hablará?', 'opcion_multiple', '{\"A\":\"Como un profesor\",\"B\":\"Como un pirata (¡Ahoy!)\",\"C\":\"No me hablará\",\"D\":\"Como un bebé\"}', 'B', 0),
(69, 18, '¿La IA sabe quién eres si no te presentas?', 'opcion_multiple', '{\"A\":\"Sí, me ve por la cámara\",\"B\":\"No, solo sabe lo que yo le escribo\",\"C\":\"Lo adivina\",\"D\":\"Me conoce de la calle\"}', 'B', 0),
(70, 18, 'Si la IA te cuenta un cuento fantástico, ¿de dónde sacó la idea?', 'opcion_multiple', '{\"A\":\"De sus sueños\",\"B\":\"De los datos que aprendió\",\"C\":\"Se la robó a un vecino\",\"D\":\"De un libro real\"}', 'B', 0),
(71, 18, '¿Qué pasa si le dices \"Hola\" muchas veces?', 'opcion_multiple', '{\"A\":\"Se enoja\",\"B\":\"Se rompe\",\"C\":\"Te responde \\\"Hola\\\" cada vez\",\"D\":\"Se apaga\"}', 'C', 0),
(72, 18, '¿Cuál es la mejor forma de pedirle algo a la IA?', 'opcion_multiple', '{\"A\":\"Gritando\",\"B\":\"Escribiendo claro y con detalles\",\"C\":\"No pidiéndole nada\",\"D\":\"Mandándole un dibujo\"}', 'B', 0),
(73, 15, 'Si quieres que el chatbot te dé una respuesta muy detallada, ¿cuál es la mejor técnica?', 'opcion_multiple', '{\"A\":\"Escribir una sola palabra\",\"B\":\"Darle instrucciones claras y contexto en el Prompt\",\"C\":\"No decirle nada y esperar\",\"D\":\"Apagar y encender la pantalla\"}', 'B', 0),
(74, 15, '¿Qué sucede si le pides a la IA que sea un personaje (como un científico)? ', 'opcion_multiple', '{\"A\":\"La IA se rompe\",\"B\":\"Cambia su forma de hablar y sus conocimientos para ese rol\",\"C\":\"Empieza a cobrar dinero\",\"D\":\"No pasa nada\"}', 'B', 0),
(75, 15, '¿Por qué a veces la IA puede dar información que parece real pero es falsa?', 'opcion_multiple', '{\"A\":\"Porque nos quiere engañar\",\"B\":\"Porque es una \'Alucinación\' al predecir palabras\",\"C\":\"Porque no tiene batería\",\"D\":\"Porque odia las tareas\"}', 'B', 0),
(76, 15, 'Si estás creando un cuento con el bot y quieres cambiar el final, ¿qué debes hacer?', 'opcion_multiple', '{\"A\":\"Borrar todo\",\"B\":\"Pedirle específicamente que cambie el final en el siguiente mensaje\",\"C\":\"Llamar al profesor\",\"D\":\"No se puede cambiar\"}', 'B', 0),
(77, 15, '¿Qué significa que el chatbot tenga \'Memoria\' durante la conversación?', 'opcion_multiple', '{\"A\":\"Que sabe tu dirección\",\"B\":\"Que recuerda lo que dijeron al inicio de la charla\",\"C\":\"Que tiene internet\",\"D\":\"Que nunca se apaga\"}', 'B', 0),
(78, 15, '¿Cuál es la regla de oro al usar chatbots para investigar tareas?', 'opcion_multiple', '{\"A\":\"Creerle todo lo que diga\",\"B\":\"Verificar la información con otras fuentes\",\"C\":\"Copiar y pegar sin leer\",\"D\":\"No usarlo nunca\"}', 'B', 0),
(79, 15, 'Si el chatbot se queda callado o no responde lo que quieres, ¿qué es lo primero que debes revisar?', 'opcion_multiple', '{\"A\":\"El cable de luz\",\"B\":\"Si tu \'Prompt\' fue lo suficientemente claro\",\"C\":\"El color del teclado\",\"D\":\"Si la silla está cómoda\"}', 'B', 0),
(80, 15, '¿Qué información NO debes compartir nunca con un chatbot?', 'opcion_multiple', '{\"A\":\"Tu color favorito\",\"B\":\"Tu nombre de usuario\",\"C\":\"Contraseñas o datos privados\",\"D\":\"El nombre de tu perro\"}', 'C', 0),
(81, 15, '¿Cuál es la diferencia entre un buscador (como Google) y un Chatbot?', 'opcion_multiple', '{\"A\":\"No hay diferencia\",\"B\":\"El buscador da links, el Chatbot genera respuestas y conversa\",\"C\":\"El Chatbot es más lento\",\"D\":\"El buscador es para niños\"}', 'B', 0),
(82, 15, '¿Para qué sirve darle un \'ejemplo\' a la IA dentro de tu pregunta?', 'opcion_multiple', '{\"A\":\"Para que pierda el tiempo\",\"B\":\"Para que entienda mejor el formato de respuesta que deseas\",\"C\":\"Para que se canse\",\"D\":\"Para nada\"}', 'B', 0);
