INSERT INTO `usuarios` (`id`, `nombre_completo`, `email`, `usuario`, `password_hash`, `nivel`, `pro_tokens`, `rango`, `biografia`, `fecha_registro`, `tokens`, `avatar`, `rol`, `insignia`, `mision_actual`, `fondo`, `heroe`, `genero`) VALUES
(11, 'William Medina ', NULL, 'william1013', '$2y$10$sdGZGWFzh8jkiQhCQpb4fettVNyhfwK2IvYnYJz8BQkXkkzLQCwdu', '', 0, 'Novato', '¡Bienvenidos a mi perfil! Soy su profe de Inteligencia Artificial y el responsable detrás de este mundo digital.  Actualmente estudio 2 carreras; Ingeniería de Sistemas e Ingeniería en Ciberseguridad. Me gusta escuchar Rock, Metal y  un poco de electrónica.\r\n\r\n¿Qué hay en mi inventario de habilidades? \r\n\r\n No solo diseño juegos; me apasiona resolver problemas difíciles de  Matemáticas y enseñarlo. Además, me sumerjo en el mundo del Hacking para entender cómo proteger la red y cómo funcionan los sistemas por dentro.\r\n\r\nHe construido proyectos reales, como una IA que detecta enfermedades en plantas de palta usando solo fotos, y me encanta crear desde páginas web hasta dispositivos con microcontroladores.\r\n\r\nMi filosofía de juego: \r\n\r\n En mis clases, las matemáticas no son aburridas, son la base para entender problemas. Creo que la mejor forma de aprender es probando, fallando y volviendo a intentar. Aquí cada error es un aprendizaje que te acerca al siguiente nivel.\r\n\r\nDato curioso:  \r\n\r\nPuedo explicarte una ecuación compleja, cómo asegurar un servidor o cómo funcionan los computadores, ¡todo en la misma charla! Si tienes una duda sobre números o quieres saber cómo creé todo esta plataforma que funciona sin internet ,búscame.', '2026-01-16 15:59:19', 99999, 'img/avatars/gm_11_1770588817.gif', 'admin', NULL, 1, 'img/fondos/custom_bg_1770599426.gif', 'img/heroes/custom_hero_1770601352.gif', 'hombre'),
(12, 'Samira Carrasco Bones', NULL, 'Samira11', '$2y$10$2UkXY1.hiIpnFLavtGul0uKe2WcTZquto9PqmRAPfFip9bJ2OL2Te', 'KIDS', 0, 'Novato', 'yo soy samira  me gusta estar con mi familia .', '2026-01-27 15:03:57', 300, 'uploads/avatars/avatar_12_1770127890.jpg', 'alumno', NULL, 1, NULL, NULL, 'mujer'),
